  'lg', 'word_game', 'levels',
  'Stage 1–2 Word Practice',
  $content${"title":"Ebigambo — Stage 1–2 Words","metadata":{"ageSupport":"optional-early-reader","evidenceBoundary":"guided construction, not independent recall"},"levels":[{"id":"lg-word-game-webale-v1","order":1,"targetText":"WEBALE","question":"Which Stage 1 word means ‘thank you’?","hint":"It is used to show gratitude.","subHint":"This is the reviewed Stage 1 gratitude word.","image":"learning/lg/stage-1/thanks-webale.png"},{"id":"lg-word-game-gyendi-v1","order":2,"targetText":"GYENDI","question":"Which Stage 1 reply means ‘I am fine’?","hint":"It answers Oli otya?","subHint":"This is the reviewed Stage 1 reply.","image":"learning/lg/stage-1/reply-gyendi.png"},{"id":"lg-word-game-maama-v1","order":3,"targetText":"MAAMA","question":"Which Stage 2 word means ‘mother’?","hint":"It names a parent.","subHint":"This is a reviewed family word.","image":"learning/lg/stage-2/maama.png"},{"id":"lg-word-game-taata-v1","order":4,"targetText":"TAATA","question":"Which Stage 2 word means ‘father’?","hint":"It names a parent.","subHint":"This is a reviewed family word.","image":"learning/lg/stage-2/taata.png"},{"id":"lg-word-game-omwana-v1","order":5,"targetText":"OMWANA","question":"Which Stage 2 word means ‘child’?","hint":"It names a young person.","subHint":"This is a reviewed family word.","image":"learning/lg/stage-2/omwana.png"},{"id":"lg-word-game-ennyumba-v1","order":6,"targetText":"ENNYUMBA","question":"Which Stage 2 word means ‘house’?","hint":"People can live in it.","subHint":"This is a reviewed home word.","image":"learning/lg/stage-2/ennyumba.png"},{"id":"lg-word-game-amazzi-v1","order":7,"targetText":"AMAZZI","question":"Which Stage 2 word means ‘water’?","hint":"People drink it.","subHint":"This is a reviewed home word.","image":"learning/lg/stage-2/amazzi.png"},{"id":"lg-word-game-ekitabo-v1","order":8,"targetText":"EKITABO","question":"Which Stage 2 word means ‘book’?","hint":"It has pages to read or look at.","subHint":"This is a reviewed home word.","image":"learning/lg/stage-2/ekitabo.png"}]}$content$::jsonb,
