VALUES (
  'lg', 'counting_game', 'stages',
  'Count 1–5 in Luganda',
  $content${"title":"Okubala 1–5 — Count One to Five","metadata":{"curriculumScope":"Optional reinforcement alongside Stages 1–2","linguisticCaveat":"Standalone number labels are provided; noun-class agreement must be reviewed before expanding to counted Luganda noun phrases.","reviewStatus":"Native-language and audio review required"},"stages":[{"id":1,"order":1,"title":"Okubala 1–5 — Count 1–5","description":"Count familiar home objects from one to five and see the standalone Luganda number label.","numbersRange":{"min":1,"max":5},"levels":5,"useBunches":false,"usesCurrency":false,"prompt":"Bala ebintu. — Count the objects."}],"numbers":[{"number":1,"order":1,"targetText":"Emu","audio":"assets/audio/learning/lg/counting/emu.mp3"},{"number":2,"order":2,"targetText":"Bbiri","audio":"assets/audio/learning/lg/counting/bbiri.mp3"},{"number":3,"order":3,"targetText":"Ssatu","audio":"assets/audio/learning/lg/counting/ssatu.mp3"},{"number":4,"order":4,"targetText":"Nnya","audio":"assets/audio/learning/lg/counting/nnya.mp3"},{"number":5,"order":5,"targetText":"Ttaano","audio":"assets/audio/learning/lg/counting/ttaano.mp3"}],"culturalItems":[{"id":"counting-item-children","order":1,"name":"children / abaana","image":"learning/lg/counting/children.png"},{"id":"counting-item-books","order":2,"name":"books / ebitabo","image":"learning/lg/counting/books.png"},{"id":"counting-item-cups","order":3,"name":"cups","image":"learning/lg/counting/cups.png"},{"id":"counting-item-houses","order":4,"name":"houses / ennyumba","image":"learning/lg/counting/houses.png"},{"id":"counting-item-water-cups","order":5,"name":"cups of water / amazzi","image":"learning/lg/counting/water-cups.png"}],"currency":[]}$content$::jsonb,
  50, true, 'published',
  true, 2, TIMESTAMPTZ '2026-07-15 18:00:00+00'
)
