  'Oli otya? — A Greeting',
  $content${"id":"greetings-at-work","title":"Oli otya? — A Greeting","summary":"A short Stage 1 greeting dialogue.","metadata":{"status":"placeholder","notes":"Curriculum-linked draft. Empty images and native-language, educator, cultural, and accessibility review are required before production.","sources":[{"label":"Peace Corps Uganda, Introductory Luganda Lessons (2008)","url":"https://files.peacecorps.gov/multimedia/audio/languagelessons/uganda/UG_Luganda_Language_Lessons.PDF"},{"label":"Baby Steps curriculum guide","url":"curriculum_guide/learning-hub-curriculum-analysis.md"}]},"pages":[{"id":"greeting-story-page-1","text":"Oli otya, Kato?","translation":"How are you, Kato?","image":"learning/lg/stage-1/story-greeting-1.png","altText":"Draft illustration for: How are you, Kato?"},{"id":"greeting-story-page-2","text":"Gyendi.","translation":"I am fine.","image":"learning/lg/stage-1/story-greeting-2.png","altText":"Draft illustration for: I am fine."},{"id":"greeting-story-page-3","text":"Gyebale ko. Kale, naawe gyebale.","translation":"Thank you for your work. Okay, thank you too.","image":"learning/lg/stage-1/story-greeting-3.png","altText":"Draft illustration for: Thank you for your work. Okay, thank you too."}],"questions":[{"id":"greeting-story-q1","question":"Which phrase asks ‘How are you?’","options":["Oli otya?","Gyendi.","Webale."],"correctAnswer":0},{"id":"greeting-story-q2","question":"Which reply means ‘I am fine’ ?","options":["Gyebale ko.","Gyendi.","Oli otya?"],"correctAnswer":1}]}$content$::jsonb,
  100, true, 'published',
  true, 2, TIMESTAMPTZ '2026-07-15 18:00:00+00'
