  'Awaka — At Home',
  $content${"id":"family-at-home","title":"Awaka — At Home","summary":"A short Stage 2 family-and-home story.","metadata":{"status":"placeholder","notes":"Curriculum-linked draft. Empty images and native-language, educator, cultural, and accessibility review are required before production.","sources":[{"label":"Peace Corps Uganda, Introductory Luganda Lessons (2008)","url":"https://files.peacecorps.gov/multimedia/audio/languagelessons/uganda/UG_Luganda_Language_Lessons.PDF"},{"label":"Baby Steps curriculum guide","url":"curriculum_guide/learning-hub-curriculum-analysis.md"}]},"pages":[{"id":"helping-at-home","text":"Maama ne Taata bali mu nnyumba.","translation":"Mother and father are in the house.","image":"learning/lg/stage-2/story-home-1.png","altText":"Draft illustration for: Mother and father are in the house."},{"id":"book-at-home","text":"Omwana alina ekitabo.","translation":"The child has a book.","image":"learning/lg/stage-2/story-home-2.png","altText":"Draft illustration for: The child has a book."},{"id":"water-at-home","text":"Omwana anywa amazzi.","translation":"The child drinks water.","image":"learning/lg/stage-2/story-home-3.png","altText":"Draft illustration for: The child drinks water."},{"id":"kind-words","text":"Webale, Maama. Webale, Taata.","translation":"Thank you, Mother. Thank you, Father.","image":"learning/lg/stage-2/story-home-4.png","altText":"Draft illustration for: Thank you, Mother. Thank you, Father."}],"questions":[{"id":"home-story-q1","question":"Which Luganda word in the story means ‘child’?","options":["Maama","Omwana","Taata"],"correctAnswer":1},{"id":"home-story-q2","question":"Which Luganda word means ‘book’?","options":["Amazzi","Ennyumba","Ekitabo"],"correctAnswer":2},{"id":"home-story-q3","question":"Which Luganda word means ‘water’?","options":["Amazzi","Maama","Omwana"],"correctAnswer":0}]}$content$::jsonb,
